node_configs.exp:
group(
  last_over_time(
    k8s_container_ready{
      k8s_namespace_name="$namespace",
      k8s_cluster_name="$cluster"
    }[2m]
  ) == 0
) by (k8s_pod_name)
and on(k8s_pod_name) (
  k8s_pod_phase{
    k8s_namespace_name="$namespace",
    k8s_cluster_name="$cluster"
  } != 3
)
